import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === QUOTE: Base premiums ===
  it("empty item list returns premium of 5 G (processing fee only)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote" as const, items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it.todo("single sword returns premium of 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("single amulet returns premium of 71 G (60 base + 6 first + 5 fee)");
  it.todo("single staff returns premium of 93 G (80 base + 8 first + 5 fee)");
  it.todo("single potion returns premium of 49 G (40 base + 4 first + 5 fee)");
  it.todo("single rune component returns premium of 33 G (25 base + 2.5 first rounded up to 3 + 5 fee)");
  it.todo("two runes returns premium of 61 G (50 base + 5 first + 5 fee, rounded up)");

  // === QUOTE: Component block pricing ===
  it.todo("3 alike runes returns block premium (60 base + 6 first + 5 fee = 71 G)");
  it.todo("4 runes returns non-block premium (100 base + 10 first + 5 fee = 115 G)");
  it.todo("2 runes + 1 moonstone returns 75 base (no block, different types)");
  it.todo("3 runes + 3 moonstones returns 120 base (two separate blocks)");

  // === QUOTE: Item-specific modifiers ===
  it.todo("cursed sword adds 50% surcharge to sword base premium");
  it.todo("highly enchanted sword (enchantment >= 5) adds 30% surcharge to sword base premium");
  it.todo("cursed and highly enchanted sword has both surcharges applied");
  it.todo("enchantment 4 does not trigger high-enchantment surcharge");

  // === QUOTE: Policy-wide modifiers ===
  it.todo("long-standing customer (>= 2 years) receives 20% loyalty discount on policy base");
  it.todo("customer with exactly 2 years qualifies for loyalty discount");
  it.todo("follow-up contract (second quote) receives 15% discount on policy base");

  // === QUOTE: Multi-item policies ===
  it.todo("policy with cursed sword and plain amulet applies curse surcharge only to sword");
  it.todo("policy with multiple items sums item base premiums before policy-wide modifiers");

  // === QUOTE: Integration - modifier stacking ===
  it.todo("newcomer with cursed sword: 100 + 50 curse + 10 first + 5 fee = 165 G");
  it.todo("long-standing customer second contract cursed enchanted sword: 155 + 5 fee = 160 G");

  // === QUOTE: Rounding ===
  it.todo("premium rounds up (in MHPCO's favor) to whole G");

  // === CLAIM: Basic payout ===
  it.todo("regular sword damage 500 G returns payout 400 G (full reimbursement minus 100 deductible)");
  it.todo("component damage 200 G returns payout 100 G (full minus 100 deductible)");

  // === CLAIM: Special clauses ===
  it.todo("enchantment >= 8 reimburses at 50% of damage then deductible");
  it.todo("dragon material fully reimburses then deductible");
  it.todo("dragon material with enchantment >= 8: 50% wins then deductible");
  it.todo("dragon material with enchantment < 8: full reimbursement then deductible");

  // === CLAIM: Cap ===
  it.todo("policy cap is 2x insurance sum");
  it.todo("successive claims exhaust cap: second claim reduced to remaining cap");

  // === CLAIM: Multiple items in one event ===
  it.todo("multiple damaged items each have their own deductible");

  // === CLAIM: Validation ===
  it.todo("damage to item not in policy rejects the claim");
  it.todo("more damage entries of a type than policy covers rejects the claim");
  it.todo("negative damage amount rejects the claim");

  // === QUOTE: Validation ===
  it.todo("unknown item type in quote rejects with error");

  // === CLI integration ===
  it.todo("CLI reads scenario from stdin and writes results to stdout");
  it.todo("CLI exits with non-zero status on error and writes to stderr");
});

