I need to handle the case where items exist. The simplest approach: parse the scenario, look at items in each step, and compute a base premium for a sword (100) plus first insurance (10%) plus fee (5).

input.content:
const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      const items = step.items || [];
      let policyBase = 0;
      for (const item of items) {
        policyBase += BASE_PREMIUMS[item.type] || 0;
      }
      const firstInsurance = policyBase * 0.1;
      const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
      return { premium };
    }
  });
  return { results };
}

