        op: "quote" as const,
        items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff returns premium of 93 G (80 base + 8 first + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion returns premium of 49 G (40 base + 4 first + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });
  it("single rune component returns premium of 33 G (25 base + 2.5 first rounded up to 3 + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("two runes returns premium of 61 G (50 base + 5 first + 5 fee, rounded up)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote" as const,
        items: [{ type: "rune" }, { type: "rune" }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 61 }] });
  });

  // === QUOTE: Component block pricing ===
  it.todo("3 alike runes returns block premium (60 base + 6 first + 5 fee = 71 G)");
  it.todo("4 runes returns non-block premium (100 base + 10 first + 5 fee = 115 G)");
  it.todo("2 runes + 1 moonstone returns 75 base (no block, different types)");
  it.todo("3 runes + 3 moonstones returns 120 base (two separate blocks)");

  // === QUOTE: Item-specific modifiers ===
  it.todo("cursed sword adds 50% surcharge to sword base premium");
  it.todo("highly enchanted sword (enchantment >= 5) adds 30% surcharge to sword base premium");
  it.todo("cursed and highly enchanted sword has both surcharges applied");
  it.todo("enchantment 4 does not trigger high-enchantment surcharge");

