const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const BLOCK_PREMIUM = 60;
const BLOCK_SIZE = 3;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

function calculateItemBasePremiums(items: any[]): number {
  const componentCounts: Record<string, number> = {};
  let policyBase = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      policyBase += BASE_PREMIUMS[item.type] || 0;
    }
  }

  for (const type in componentCounts) {
    const count = componentCounts[type];
    if (count === BLOCK_SIZE) {
      policyBase += BLOCK_PREMIUM;
    } else {
      policyBase += count * COMPONENT_PREMIUM;
    }
  }

  return policyBase;
}

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      const items = step.items || [];
      const policyBase = calculateItemBasePremiums(items);
      const firstInsuranceSurcharge = policyBase * 0.1;
      const premium = Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
      return { premium };
    }
  });
  return { results };
}

